import { FunctionComponent } from "react";
import {StyledCard, Footer, DataContainer, Name, ButtonContainer} from "./index.style";
import Button from "components/Button";
import {Cat} from "app-types/cat";

interface CardProps {
    cat: Cat;

}

type Props = CardProps & React.HtmlHTMLAttributes<HTMLDivElement>;

const Card: FunctionComponent<Props> = ({cat, ...rest}) => {
    return <StyledCard $catId={cat.id} {...rest}>
        <Footer>
            <DataContainer>
                <Name>{cat.name}</Name>
            </DataContainer>
            <ButtonContainer>
                <Button variant ={"ignore"}/>
                <Button variant ={"superLike"}/>
                <Button variant ={"like"}/>
            </ButtonContainer>

        </Footer>

    </StyledCard>
}

export default Card;
